// frontend/src/components/workers/WorkerProfile.js
import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate, useLocation } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './WorkerProfile.css';

const WorkerProfile = () => {
    const alert = useAlert();
    const { id } = useParams();
    const navigate = useNavigate();
    const location = useLocation();
    const { user } = useAuth();

    const [worker, setWorker] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [activeSection, setActiveSection] = useState(null);
    const [formData, setFormData] = useState({
        primary_skill: '',
        skills: [],
        experience_years: 0,
        hourly_rate_min: 100,
        hourly_rate_max: 300,
        available_days: '',
        available_hours: '',
        travel_radius_km: 5,
        bio: '',
        rating: 0,
        total_jobs: 0,
        completed_jobs: 0,
        cancellation_rate: 0
    });
    const [newSkill, setNewSkill] = useState('');
    const [updating, setUpdating] = useState(false);
    const [updateSuccess, setUpdateSuccess] = useState('');

    // Get navigation state
    const fromJob = location.state?.from === 'job';
    const jobId = location.state?.jobId;
    const jobTitle = location.state?.jobTitle;

    useEffect(() => {
        loadWorkerProfile();
    }, [id]);

    // Helper function to parse skills (handles both array and string)
    const parseSkills = (skillsData) => {
        if (!skillsData) return [];
        if (Array.isArray(skillsData)) return skillsData;
        if (typeof skillsData === 'string') {
            try {
                // Try to parse JSON string
                const parsed = JSON.parse(skillsData);
                return Array.isArray(parsed) ? parsed : [];
            } catch (e) {
                // If not valid JSON, split by comma
                return skillsData.split(',').map(s => s.trim()).filter(s => s);
            }
        }
        return [];
    };

    const loadWorkerProfile = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/workers/${id}`);
            if (response.data.success) {
                const workerData = response.data.data;

                // Parse skills properly
                const parsedSkills = parseSkills(workerData.skills);

                setWorker({
                    ...workerData,
                    skills: parsedSkills
                });

                // Initialize form data with existing values
                setFormData({
                    primary_skill: workerData.primary_skill || '',
                    skills: parsedSkills,
                    experience_years: workerData.experience_years || 0,
                    hourly_rate_min: workerData.hourly_rate_min || 100,
                    hourly_rate_max: workerData.hourly_rate_max || 300,
                    available_days: workerData.available_days || '',
                    available_hours: workerData.available_hours || '',
                    travel_radius_km: workerData.travel_radius_km || 5,
                    bio: workerData.bio || '',
                    rating: workerData.rating || 0,
                    total_jobs: workerData.total_jobs || 0,
                    completed_jobs: workerData.completed_jobs || 0,
                    cancellation_rate: workerData.cancellation_rate || 0
                });
            } else {
                setError('Worker not found');
            }
        } catch (error) {
            console.error('Error loading worker:', error);
            setError('Failed to load worker profile');
        } finally {
            setLoading(false);
        }
    };

    const handleInputChange = (e) => {
        const { name, value, type } = e.target;
        setFormData({
            ...formData,
            [name]: type === 'number' ? (value ? parseInt(value) : 0) : value
        });
    };

    // Add a new skill
    const handleAddSkill = () => {
        if (newSkill.trim() && !formData.skills.includes(newSkill.trim())) {
            setFormData({
                ...formData,
                skills: [...formData.skills, newSkill.trim()]
            });
            setNewSkill('');
        }
    };

    // Remove a skill
    const handleRemoveSkill = (skillToRemove) => {
        setFormData({
            ...formData,
            skills: formData.skills.filter(skill => skill !== skillToRemove)
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setUpdating(true);
        setError('');
        setUpdateSuccess('');

        try {
            console.log('Submitting form data:', formData);

            // Prepare data for backend - only send editable fields
            const dataToSend = {
                primary_skill: formData.primary_skill || '',
                skills: formData.skills, // Send as array, backend will stringify
                experience_years: parseInt(formData.experience_years) || 0,
                hourly_rate_min: parseInt(formData.hourly_rate_min) || 100,
                hourly_rate_max: parseInt(formData.hourly_rate_max) || 300,
                available_days: formData.available_days || '',
                available_hours: formData.available_hours || '',
                travel_radius_km: parseInt(formData.travel_radius_km) || 5,
                bio: formData.bio || ''
            };

            console.log('Data being sent to backend:', dataToSend);

            const response = await api.put('/worker/profile', dataToSend);

            if (response.data.success) {
                alert.success('Profile updated successfully!');
                setActiveSection(null);
                // Don't setIsEditing false here - keep in edit mode but close section
                loadWorkerProfile();
                setTimeout(() => setUpdateSuccess(''), 3000);
            } else {
                alert.error(response.data.message || 'Failed to update profile');
            }
        } catch (error) {
            console.error('Update error:', error);
            console.error('Error response:', error.response?.data);
            alert.error(error.response?.data?.message || 'Network error. Please try again.');
        } finally {
            setUpdating(false);
        }
    };

    const handleCancel = () => {
        setActiveSection(null);
        // Reset form data to original worker data
        setFormData({
            primary_skill: worker.primary_skill || '',
            skills: worker.skills || [],
            experience_years: worker.experience_years || 0,
            hourly_rate_min: worker.hourly_rate_min || 100,
            hourly_rate_max: worker.hourly_rate_max || 300,
            available_days: worker.available_days || '',
            available_hours: worker.available_hours || '',
            travel_radius_km: worker.travel_radius_km || 5,
            bio: worker.bio || '',
            rating: worker.rating || 0,
            total_jobs: worker.total_jobs || 0,
            completed_jobs: worker.completed_jobs || 0,
            cancellation_rate: worker.cancellation_rate || 0
        });
        setNewSkill('');
    };

    // Safe formatting functions
    const formatRating = (rating) => {
        if (rating === null || rating === undefined) return '0.0';
        const numRating = parseFloat(rating);
        return isNaN(numRating) ? '0.0' : numRating.toFixed(1);
    };

    const formatNumber = (num) => {
        if (num === null || num === undefined) return '0';
        const parsed = parseInt(num);
        return isNaN(parsed) ? '0' : parsed.toString();
    };

    const formatCurrency = (amount) => {
        if (amount === null || amount === undefined) return '0';
        const parsed = parseFloat(amount);
        return isNaN(parsed) ? '0' : parsed.toFixed(0);
    };

    const formatPercentage = (rate) => {
        if (rate === null || rate === undefined) return '0%';
        const parsed = parseFloat(rate);
        return isNaN(parsed) ? '0%' : parsed.toFixed(1) + '%';
    };

    const handleBack = () => {
        if (fromJob && jobId) {
            navigate(`/jobs/${jobId}`);
        } else {
            navigate(-1);
        }
    };

    const handleGoToMyProfile = () => {
        if (user) {
            navigate(`/workers/${user.id}`);
        }
    };

    if (loading) {
        return (
            <div className="loading-container">
                <div className="loading-spinner">Loading profile...</div>
            </div>
        );
    }

    if (error || !worker) {
        return (
            <div className="error-container">
                <h2>❌ Error</h2>
                <p>{error || 'Worker not found'}</p>
                <button onClick={handleBack} className="btn-primary">
                    Go Back
                </button>
            </div>
        );
    }

    // Check if this is the logged-in user's profile
    const isOwnProfile = user?.id === worker.user_id;

    // Ensure skills is an array for rendering
    const safeSkills = Array.isArray(worker.skills) ? worker.skills : [];

    // Debug info
    console.log('========== PROFILE DEBUG ==========');
    console.log('Logged in user ID:', user?.id);
    console.log('Profile owner user_id:', worker.user_id);
    console.log('Is own profile?', isOwnProfile);
    console.log('Skills data type:', typeof worker.skills);
    console.log('Skills value:', worker.skills);
    console.log('Safe skills array:', safeSkills);
    console.log('====================================');

    return (
        <div className="worker-profile-container">
            <div className="worker-profile">
                {/* Back Button */}
                <div className="back-navigation">
                    <button onClick={handleBack} className="back-button">
                        ← {fromJob ? `Back to Job: ${jobTitle || 'Job Details'}` : 'Back'}
                    </button>
                    {fromJob && (
                        <span className="navigation-context">
                            Viewing worker profile
                        </span>
                    )}
                </div>

                {/* Success Message */}
                {updateSuccess && (
                    <div className="success-message">
                        ✅ {updateSuccess}
                    </div>
                )}

                {/* Error Message */}
                {error && (
                    <div className="error-message">
                        ❌ {error}
                    </div>
                )}

                {/* Navigation helper - shows when viewing wrong profile */}
                {user && worker.user_id !== user.id && (
                    <div className="quick-action-card" style={{ marginBottom: '20px', background: '#E1F5FE' }}>
                        <p>You're viewing <strong>{worker.name}'s</strong> profile.</p>
                        <p>Your profile ID is <strong>{user.id}</strong>.</p>
                        <button 
                            onClick={handleGoToMyProfile}
                            className="btn-primary"
                        >
                            Go to My Profile
                        </button>
                    </div>
                )}

                {/* Profile Header */}
                <div className="profile-header">
                    <div className="profile-avatar">
                        {worker.name?.charAt(0) || '👤'}
                    </div>
                    <div className="profile-title">
                        <h1>{worker.name || 'Unknown Worker'}</h1>
                        <p className="worker-location">
                            <span className="location-icon">📍</span>
                            {worker.township || 'Location not specified'}
                        </p>
                        <div className="worker-badges">
                            {worker.is_verified && (
                                <span className="badge verified">✓ Verified</span>
                            )}
                            <span className="badge level">
                                Level {worker.verification_level || 0}
                            </span>
                        </div>
                    </div>

                    {/* Main Edit button - only shows on own profile */}
                    {isOwnProfile && !isEditing && (
                        <button 
                            className="btn-edit"
                            onClick={() => setIsEditing(true)}
                        >
                            ✎ Complete Your Profile
                        </button>
                    )}

                    {/* Cancel Edit button - only shows when editing own profile */}
                    {isOwnProfile && isEditing && (
                        <button 
                            className="btn-cancel-edit"
                            onClick={() => {
                                setIsEditing(false);
                                handleCancel();
                            }}
                        >
                            ✕ Cancel Editing
                        </button>
                    )}
                </div>

                {/* Stats Cards */}
                <div className="profile-stats">
                    <div className="stat-card">
                        <span className="stat-value">
                            {formatRating(worker.rating)}
                        </span>
                        <span className="stat-label">Rating</span>
                    </div>
                    <div className="stat-card">
                        <span className="stat-value">
                            {formatNumber(worker.completed_jobs)}
                        </span>
                        <span className="stat-label">Jobs Done</span>
                    </div>
                    <div className="stat-card">
                        <span className="stat-value">
                            {formatNumber(worker.total_jobs)}
                        </span>
                        <span className="stat-label">Total Jobs</span>
                    </div>
                    <div className="stat-card">
                        <span className="stat-value">
                            {formatPercentage(worker.cancellation_rate)}
                        </span>
                        <span className="stat-label">Cancellation Rate</span>
                    </div>
                </div>

                {/* Profile Completion Message - shows if profile is incomplete */}
                {isOwnProfile && !isEditing && (
                    <div className="completion-message">
                        <p>✨ Complete your profile to get more jobs! Add your skills, rates, and availability.</p>
                    </div>
                )}

                {/* Skills Section */}
                <div className="details-section">
                    <div className="section-header">
                        <h3>🛠️ Skills & Expertise</h3>
                        {isOwnProfile && isEditing && activeSection !== 'skills' && (
                            <button 
                                className="btn-edit-section"
                                onClick={() => setActiveSection('skills')}
                            >
                                ✎ {worker.primary_skill ? 'Edit Skills' : 'Add Skills'}
                            </button>
                        )}
                    </div>

                    {isOwnProfile && isEditing && activeSection === 'skills' ? (
                        <div className="edit-section">
                            <div className="form-group">
                                <label>Primary Skill *</label>
                                <select
                                    name="primary_skill"
                                    value={formData.primary_skill}
                                    onChange={handleInputChange}
                                    required
                                >
                                    <option value="">Select your main skill</option>
                                    <option value="Gardening">Gardening</option>
                                    <option value="Cleaning">Cleaning</option>
                                    <option value="Plumbing">Plumbing</option>
                                    <option value="Electrical">Electrical</option>
                                    <option value="Painting">Painting</option>
                                    <option value="Building">Building</option>
                                    <option value="Carpentry">Carpentry</option>
                                    <option value="Moving">Moving</option>
                                    <option value="Delivery">Delivery</option>
                                    <option value="Handyman">Handyman</option>
                                </select>
                            </div>

                            <div className="form-group">
                                <label>Years of Experience</label>
                                <div className="number-input-group">
                                    <button 
                                        type="button" 
                                        className="number-btn decrease"
                                        onClick={() => {
                                            const newValue = Math.max(0, (formData.experience_years || 0) - 1);
                                            setFormData({...formData, experience_years: newValue});
                                        }}
                                    >
                                        −
                                    </button>
                                    <input
                                        type="number"
                                        name="experience_years"
                                        value={formData.experience_years || 0}
                                        onChange={handleInputChange}
                                        min="0"
                                        max="50"
                                        className="number-input"
                                    />
                                    <button 
                                        type="button" 
                                        className="number-btn increase"
                                        onClick={() => {
                                            const newValue = Math.min(50, (formData.experience_years || 0) + 1);
                                            setFormData({...formData, experience_years: newValue});
                                        }}
                                    >
                                        +
                                    </button>
                                </div>
                                <div className="input-range-indicator">
                                    <span>Min: 0</span>
                                    <span className="current-value">Current: {formData.experience_years || 0} years</span>
                                    <span>Max: 50</span>
                                </div>
                            </div>

                            <div className="form-group">
                                <label>Other Skills</label>
                                <div className="skills-input-group">
                                    <input
                                        type="text"
                                        value={newSkill}
                                        onChange={(e) => setNewSkill(e.target.value)}
                                        placeholder="Enter a skill (e.g., Plumbing)"
                                        className="skill-input"
                                    />
                                    <button 
                                        type="button"
                                        className="btn-add-skill"
                                        onClick={handleAddSkill}
                                    >
                                        + Add
                                    </button>
                                </div>

                                <div className="skills-list-edit">
                                    {formData.skills.map((skill, index) => (
                                        <div key={index} className="skill-item">
                                            <span>{skill}</span>
                                            <button 
                                                type="button"
                                                className="btn-remove-skill"
                                                onClick={() => handleRemoveSkill(skill)}
                                            >
                                                ×
                                            </button>
                                        </div>
                                    ))}
                                    {formData.skills.length === 0 && (
                                        <p className="no-skills">No additional skills added yet</p>
                                    )}
                                </div>
                                <small>Add skills to appear in more job searches</small>
                            </div>

                            <div className="section-actions">
                                <button 
                                    type="button"
                                    className="btn-save-section"
                                    onClick={handleSubmit}
                                    disabled={updating}
                                >
                                    {updating ? 'Saving...' : 'Save Skills'}
                                </button>
                                <button 
                                    type="button"
                                    className="btn-cancel-section"
                                    onClick={() => setActiveSection(null)}
                                >
                                    Cancel
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="skills-list">
                            {worker.primary_skill ? (
                                <span className="skill-tag primary">
                                    {worker.primary_skill} (Primary)
                                </span>
                            ) : (
                                <p className="no-skills">No primary skill set</p>
                            )}
                            {safeSkills.map((skill, index) => (
                                <span key={index} className="skill-tag">
                                    {skill}
                                </span>
                            ))}
                            {worker.experience_years > 0 && (
                                <p className="experience-text">
                                    📅 {worker.experience_years} years of experience
                                </p>
                            )}
                        </div>
                    )}
                </div>

                {/* Rest of your sections remain the same... */}
                {/* Rates Section */}
                <div className="details-section">
                    <div className="section-header">
                        <h3>💰 Rates & Travel</h3>
                        {isOwnProfile && isEditing && activeSection !== 'rates' && (
                            <button 
                                className="btn-edit-section"
                                onClick={() => setActiveSection('rates')}
                            >
                                ✎ {worker.hourly_rate_min ? 'Update Rates' : 'Set Rates'}
                            </button>
                        )}
                    </div>

                    {isOwnProfile && isEditing && activeSection === 'rates' ? (
                        <div className="edit-section">
                        <div className="form-row">
                            <div className="form-group">
                                <label>Hourly Rate Min (R)</label>
                                <div className="number-input-group">
                                    <button 
                                        type="button" 
                                        className="number-btn decrease"
                                        onClick={() => {
                                            const newValue = Math.max(0, (formData.hourly_rate_min || 100) - 50);
                                            setFormData({...formData, hourly_rate_min: newValue});
                                        }}
                                    >
                                        −
                                    </button>
                                    <input
                                        type="number"
                                        name="hourly_rate_min"
                                        value={formData.hourly_rate_min || 100}
                                        onChange={handleInputChange}
                                        min="0"
                                        step="50"
                                        className="number-input"
                                    />
                                    <button 
                                        type="button" 
                                        className="number-btn increase"
                                        onClick={() => {
                                            const newValue = (formData.hourly_rate_min || 100) + 50;
                                            setFormData({...formData, hourly_rate_min: newValue});
                                        }}
                                    >
                                        +
                                    </button>
                                </div>
                                <div className="input-range-indicator">
                                    <span>Min: R0</span>
                                    <span className="current-value">Current: R{formData.hourly_rate_min || 100}</span>
                                </div>
                            </div>

                            <div className="form-group">
                                <label>Hourly Rate Max (R)</label>
                                <div className="number-input-group">
                                    <button 
                                        type="button" 
                                        className="number-btn decrease"
                                        onClick={() => {
                                            const newValue = Math.max(formData.hourly_rate_min || 100, (formData.hourly_rate_max || 300) - 50);
                                            setFormData({...formData, hourly_rate_max: newValue});
                                        }}
                                    >
                                        −
                                    </button>
                                    <input
                                        type="number"
                                        name="hourly_rate_max"
                                        value={formData.hourly_rate_max || 300}
                                        onChange={handleInputChange}
                                        min={formData.hourly_rate_min || 100}
                                        step="50"
                                        className="number-input"
                                    />
                                    <button 
                                        type="button" 
                                        className="number-btn increase"
                                        onClick={() => {
                                            const newValue = (formData.hourly_rate_max || 300) + 50;
                                            setFormData({...formData, hourly_rate_max: newValue});
                                        }}
                                    >
                                        +
                                    </button>
                                </div>
                                <div className="input-range-indicator">
                                    <span>Min: R{formData.hourly_rate_min || 100}</span>
                                    <span className="current-value">Current: R{formData.hourly_rate_max || 300}</span>
                                </div>
                            </div>
                        </div>

                        <div className="form-group">
                            <label>Travel Radius (km)</label>
                            <div className="number-input-group">
                                <button 
                                    type="button" 
                                    className="number-btn decrease"
                                    onClick={() => {
                                        const newValue = Math.max(1, (formData.travel_radius_km || 5) - 1);
                                        setFormData({...formData, travel_radius_km: newValue});
                                    }}
                                >
                                    −
                                </button>
                                <input
                                    type="number"
                                    name="travel_radius_km"
                                    value={formData.travel_radius_km || 5}
                                    onChange={handleInputChange}
                                    min="1"
                                    max="100"
                                    className="number-input"
                                />
                                <button 
                                    type="button" 
                                    className="number-btn increase"
                                    onClick={() => {
                                        const newValue = Math.min(100, (formData.travel_radius_km || 5) + 1);
                                        setFormData({...formData, travel_radius_km: newValue});
                                    }}
                                >
                                    +
                                </button>
                            </div>
                            <div className="input-range-indicator">
                                <span>Min: 1km</span>
                                <span className="current-value">Current: {formData.travel_radius_km || 5}km</span>
                                <span>Max: 100km</span>
                            </div>
                        </div>

                            <div className="section-actions">
                                <button 
                                    type="button"
                                    className="btn-save-section"
                                    onClick={handleSubmit}
                                    disabled={updating}
                                >
                                    {updating ? 'Saving...' : 'Save Rates'}
                                </button>
                                <button 
                                    type="button"
                                    className="btn-cancel-section"
                                    onClick={() => setActiveSection(null)}
                                >
                                    Cancel
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="rates-info">
                            <div className="rate-item">
                                <span className="rate-label">Hourly Rate:</span>
                                <span className="rate-value">
                                    {worker.hourly_rate_min ? (
                                        `R${formatCurrency(worker.hourly_rate_min)} - R${formatCurrency(worker.hourly_rate_max)}`
                                    ) : (
                                        'Not set'
                                    )}
                                </span>
                            </div>
                            <div className="rate-item">
                                <span className="rate-label">Travel Radius:</span>
                                <span className="rate-value">
                                    {worker.travel_radius_km ? `${formatNumber(worker.travel_radius_km)} km` : 'Not set'}
                                </span>
                            </div>
                        </div>
                    )}
                </div>

                {/* Availability Section */}
                <div className="details-section">
                    <div className="section-header">
                        <h3>📅 Availability</h3>
                        {isOwnProfile && isEditing && activeSection !== 'availability' && (
                            <button 
                                className="btn-edit-section"
                                onClick={() => setActiveSection('availability')}
                            >
                                ✎ {worker.available_days ? 'Update Availability' : 'Set Availability'}
                            </button>
                        )}
                    </div>

                    {isOwnProfile && isEditing && activeSection === 'availability' ? (
                        <div className="edit-section">
                            <div className="form-group">
                                <label>Available Days</label>
                                <input
                                    type="text"
                                    name="available_days"
                                    value={formData.available_days}
                                    onChange={handleInputChange}
                                    placeholder="e.g., Monday - Friday"
                                />
                                <small>e.g., Weekdays, Weekends, Monday-Friday</small>
                            </div>

                            <div className="form-group">
                                <label>Available Hours</label>
                                <input
                                    type="text"
                                    name="available_hours"
                                    value={formData.available_hours}
                                    onChange={handleInputChange}
                                    placeholder="e.g., 9am - 5pm"
                                />
                                <small>e.g., 8am-6pm, Evenings, Flexible</small>
                            </div>

                            <div className="section-actions">
                                <button 
                                    type="button"
                                    className="btn-save-section"
                                    onClick={handleSubmit}
                                    disabled={updating}
                                >
                                    {updating ? 'Saving...' : 'Save Availability'}
                                </button>
                                <button 
                                    type="button"
                                    className="btn-cancel-section"
                                    onClick={() => setActiveSection(null)}
                                >
                                    Cancel
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="availability-info">
                            <div className="avail-item">
                                <span className="avail-label">Days:</span>
                                <span className="avail-value">
                                    {worker.available_days || 'Not specified'}
                                </span>
                            </div>
                            <div className="avail-item">
                                <span className="avail-label">Hours:</span>
                                <span className="avail-value">
                                    {worker.available_hours || 'Not specified'}
                                </span>
                            </div>
                        </div>
                    )}
                </div>

                {/* Bio Section */}
                <div className="details-section">
                    <div className="section-header">
                        <h3>📝 About</h3>
                        {isOwnProfile && isEditing && activeSection !== 'bio' && (
                            <button 
                                className="btn-edit-section"
                                onClick={() => setActiveSection('bio')}
                            >
                                ✎ {worker.bio ? 'Edit Bio' : 'Add Bio'}
                            </button>
                        )}
                    </div>

                    {isOwnProfile && isEditing && activeSection === 'bio' ? (
                        <div className="edit-section">
                            <div className="form-group">
                                <label>Tell clients about yourself</label>
                                <textarea
                                    name="bio"
                                    value={formData.bio}
                                    onChange={handleInputChange}
                                    placeholder="Describe your experience, skills, and what makes you a great worker..."
                                    rows="5"
                                />
                                <small>This helps clients get to know you better</small>
                            </div>

                            <div className="section-actions">
                                <button 
                                    type="button"
                                    className="btn-save-section"
                                    onClick={handleSubmit}
                                    disabled={updating}
                                >
                                    {updating ? 'Saving...' : 'Save Bio'}
                                </button>
                                <button 
                                    type="button"
                                    className="btn-cancel-section"
                                    onClick={() => setActiveSection(null)}
                                >
                                    Cancel
                                </button>
                            </div>
                        </div>
                    ) : (
                        worker.bio ? (
                            <p className="bio-text">{worker.bio}</p>
                        ) : (
                            <p className="no-bio">No bio provided yet</p>
                        )
                    )}
                </div>

                {/* Performance Stats Section - Read Only */}
                <div className="details-section">
                    <h3>📊 Performance Stats</h3>
                    <div className="performance-stats-grid">
                        <div className="perf-stat-item">
                            <span className="perf-stat-label">Rating</span>
                            <span className="perf-stat-value">{formatRating(worker.rating)} ⭐</span>
                        </div>
                        <div className="perf-stat-item">
                            <span className="perf-stat-label">Total Jobs</span>
                            <span className="perf-stat-value">{formatNumber(worker.total_jobs)}</span>
                        </div>
                        <div className="perf-stat-item">
                            <span className="perf-stat-label">Completed</span>
                            <span className="perf-stat-value">{formatNumber(worker.completed_jobs)}</span>
                        </div>
                        <div className="perf-stat-item">
                            <span className="perf-stat-label">Cancellation Rate</span>
                            <span className="perf-stat-value">{formatPercentage(worker.cancellation_rate)}</span>
                        </div>
                    </div>
                </div>

                {/* Reviews Section */}
                <div className="details-section">
                    <h3>⭐ Reviews</h3>
                    {worker.reviews?.length > 0 ? (
                        <div className="reviews-list">
                            {worker.reviews.map((review, index) => (
                                <div key={index} className="review-item">
                                    <div className="review-header">
                                        <span className="reviewer">
                                            {review.reviewer_name || 'Anonymous'}
                                        </span>
                                        <span className="review-rating">
                                            {'⭐'.repeat(review.rating || 0)}
                                        </span>
                                    </div>
                                    <p className="review-comment">
                                        {review.comment || 'No comment'}
                                    </p>
                                    <p className="review-job">
                                        {review.job_title || 'Job'}
                                    </p>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <p className="no-reviews">No reviews yet</p>
                    )}
                </div>

                {/* Completed Jobs Section */}
                <div className="details-section">
                    <h3>✅ Completed Jobs</h3>
                    {worker.completed_jobs?.length > 0 ? (
                        <div className="jobs-list">
                            {worker.completed_jobs.map((job, index) => (
                                <div key={index} className="job-item">
                                    <h4>{job.title || 'Job'}</h4>
                                    <p>{job.completion_notes || 'Completed'}</p>
                                    <Link to={`/jobs/${job.id}`}>
                                        View Details →
                                    </Link>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <p className="no-jobs">No completed jobs yet</p>
                    )}
                </div>
            </div>
        </div>
    );
};

export default WorkerProfile;
